class Solution {
    public int magicalString(int n) {
        int[] s = new int[n + 1];
        s[0] = 1;
        s[1] = 2;
        s[2] = 2;
        int head = 2, tail = 3, count = 1;
        while (tail <= n) {
            int num = s[head];
            int val = 3 - s[tail - 1];
            for (int i = 0; i < num && tail <= n; i++) {
                s[tail++] = val;
                if (val == 1) count++;
            }
            head++;
        }
        return count;
    }
}
